import { _decorator, Component, director, Node, Label, Button, ScrollView, Prefab, instantiate } from 'cc';
import { GameManager } from '../Core/GameManager';

const { ccclass, property } = _decorator;

@ccclass('FriendScene')
export class FriendScene extends Component {
    @property(Button)
    backBtn: Button = null;
    
    @property(Button)
    addFriendBtn: Button = null;
    
    @property(ScrollView)
    friendListScrollView: ScrollView = null;
    
    @property(Node)
    friendItemPrefab: Node = null;
    
    private friends = [
        { id: 1, name: '财神小弟', level: 10, status: 'online' },
        { id: 2, name: '招财猫', level: 15, status: 'offline' },
        { id: 3, name: '金蟾子', level: 8, status: 'online' }
    ];
    
    onLoad() {
        this.backBtn.node.on(Button.EventType.CLICK, this.onBack, this);
        this.addFriendBtn.node.on(Button.EventType.CLICK, this.onAddFriend, this);
    }
    
    start() {
        this.updateFriendList();
    }
    
    updateFriendList() {
        const content = this.friendListScrollView.content;
        content.removeAllChildren();
        
        for (const friend of this.friends) {
            const item = instantiate(this.friendItemPrefab);
            
            item.getChildByName('NameLabel').getComponent(Label).string = friend.name;
            item.getChildByName('LevelLabel').getComponent(Label).string = `Lv.${friend.level}`;
            item.getChildByName('StatusLabel').getComponent(Label).string = 
                friend.status === 'online' ? '🟢 在线' : '⚫ 离线';
            
            // 拜访按钮
            const visitBtn = item.getChildByName('VisitBtn').getComponent(Button);
            visitBtn.node.on(Button.EventType.CLICK, () => this.onVisitFriend(friend.id), this);
            
            // 赠送按钮
            const giftBtn = item.getChildByName('GiftBtn').getComponent(Button);
            giftBtn.node.on(Button.EventType.CLICK, () => this.onGiftFriend(friend.id), this);
            
            content.addChild(item);
        }
    }
    
    onAddFriend() {
        // 添加好友逻辑
        const friendId = prompt('请输入好友ID:');
        if (friendId) {
            console.log(`发送好友请求给${friendId}`);
        }
    }
    
    onVisitFriend(friendId: number) {
        console.log(`拜访好友${friendId}`);
        // 进入好友庙宇场景
    }
    
    onGiftFriend(friendId: number) {
        console.log(`赠送礼物给好友${friendId}`);
        // 显示礼物选择界面
    }
    
    onBack() {
        director.loadScene('MainScene');
    }
}
